class Node:
    def __init__(self, data):
        self.data = data
        self.next = None

class LinkedList:
    def __init__(self):
        self.head = None

    def append(self, data):
        new_node = Node(data)
        if not self.head:
            self.head = new_node
            return
        last = self.head
        while last.next:
            last = last.next
        last.next = new_node

    def print_list(self):
        current = self.head
        elements = []
        while current:
            elements.append(str(current.data))
            current = current.next
        print(" -> ".join(elements) if elements else "Empty List")

    def delete_n_after_m(self, M, N):
        if N == 0:
            return

        if not self.head:
            return

        if M == 0:
            current = self.head
            for _ in range(N):
                if current is None:
                    break
                current = current.next
            self.head = current
            return

        current = self.head
        prev_m_node = None

        count = 0
        while current and count < M:
            prev_m_node = current
            current = current.next
            count += 1

        if count < M or prev_m_node is None:
            return

        if prev_m_node.next is None:
             return

        node_after_delete_block = current

        for _ in range(N):
            if node_after_delete_block is None:
                break
            node_after_delete_block = node_after_delete_block.next

        prev_m_node.next = node_after_delete_block
